member.example:
Bind the AudioSource mute property using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceMuteBinder _mute;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _mute;
    }


Bind the AudioSource mute property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private AudioSource _audioSource;
        
        private AudioSourceMuteBinder Mute =>
            new(_audioSource);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _mute;
    }
